on conflict (id) do update set full_name = excluded.full_name, role = excluded.role, department = excluded.department, is_active = excluded.is_active;

on conflict (ticket_number) do nothing;

select id, created_by, 'Initial request logged with business impact and affected user details.', false from public.tickets
where ticket_number in ('IT-00001', 'IT-00003', 'IT-00012')
on conflict do nothing;

select id, coalesce(assigned_to, '6f737dfb-0256-4d6a-ae6e-385e2809f6ab'), 'Internal triage started. Checking logs and recent configuration changes.', true from public.tickets
where ticket_number in ('IT-00001', 'IT-00002', 'IT-00009')
on conflict do nothing;

select id, created_by, 'created ticket', null, status from public.tickets
on conflict do nothing;
